async function skill(bot, goals) {
    try {
        if (!bot || !bot.inventory) {
            return "Error: Bot is not ready.";
        }

        const blocksToCheck = ['stone'];
        const startPosition = bot.entity.position;
        const maxDistance = 10;
        let targetBlock = null;

        for (let x = -maxDistance; x <= maxDistance; x++) {
            for (let y = -maxDistance; y <= maxDistance; y++) {
                for (let z = -maxDistance; z <= maxDistance; z++) {
                    const position = startPosition.offset(x, y, z);
                    const block = bot.blockAt(position);

                    if (block && blocksToCheck.includes(block.name)) {
                        targetBlock = block;
                        break;
                    }
                }
                if (targetBlock) break;
            }
            if (targetBlock) break;
        }

        if (!targetBlock) {
            return "Error: No mineable stone block found within range.";
        }

        await bot.dig(targetBlock);
        return "Success: Stone block mined successfully.";
    } catch (error) {
        return `Error: ${error.message}`;
    }
}

