async function skill(bot, goals) {
  const targetBlockType = 'spruce_log';
  let collectedItems = 0;

  async function gatherWood() {
    const block = bot.findBlock({
      matching: (block) => block.name === targetBlockType
    });

    if (!block) return '목표 블록을 찾을 수 없습니다.';

    try {
      await bot.dig(block);

      const droppedItems = bot.entities.filter(ent => ent.objectType === 'item');
      for (const item of droppedItems) {
        const itemBlockName = item.metadata[7]?.name;
        if (itemBlockName === targetBlockType) {
          collectedItems++;
          bot.pathfinder.setGoal(new bot.pathfinder.goals.GoalNear(item.position.x, item.position.y, item.position.z, 1));
          if (collectedItems >= 10) return '성공적으로 나무를 수집했습니다.';
        }
      }

    } catch (error) {
      return '채굴 중 오류 발생: ' + error.message;
    }

    bot.once('physicTick', gatherWood);
  }

  gatherWood();
  return '나무 수집을 시작합니다.';
}

