async function skill(bot, goals) {
  try {
    const workbench = bot.findBlock({
      matching: block => block.name === 'crafting_table',
      maxDistance: 64
    });

    if (!workbench) {
      const wood = bot.inventory.items().find(item => item.name.includes('log') || item.name.includes('wood'));
      if (!wood) return 'No wood available to craft a workbench';

      const workbenchRecipe = bot.recipesFor(58)[0];
      if (!workbenchRecipe) return 'No recipe found for crafting table';

      await bot.craft(workbenchRecipe, 1);
    }

    const targetPosition = workbench ? workbench.position : bot.entity.position.offset(1, 0, 0);

    await bot.pathfinder.goto(new goals.GoalNear(targetPosition.x, targetPosition.y, targetPosition.z, 1));

    if (!workbench) {
      await bot.equip(58, 'hand');
      await bot.placeBlock(bot.blockAt(bot.entity.position.offset(0, -1, 0)), new Vec3(0, 1, 0));
    }

    return 'Successfully prepared crafting station for crafting wooden tools';
  } catch (error) {
    return `Failed to prepare crafting station: ${error.message}`;
  }
}
